      ['analytics', 'grey', report.greyCount.toString()],
      ['analytics', 'early', report.earlyCount.toString()],
      ['analytics', 'late', report.lateCount.toString()],
      ['analytics', 'best_streak', report.longestStableStreak.toString()],
