        try {
          await CloudHistoryService().deleteSession(session.id);
        } catch (e) {
          syncError = e;
          debugPrint('Cloud history delete error: $e');
        }
      }

      if (!mounted) return;
      await _refreshLocalSessions();
      if (!mounted) return;
      setState(() {
        _syncWarning = syncError == null
